import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔核之力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/3.心智类/魔核之力.md","filePath":"4.资源分区/2.改造与功法/改造/3.心智类/魔核之力.md"}'),s={name:"4.资源分区/2.改造与功法/改造/3.心智类/魔核之力.md"};function o(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"魔核之力",tabindex:"-1"},[p("魔核之力 "),r("a",{class:"header-anchor",href:"#魔核之力","aria-label":'Permalink to "魔核之力"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调014")])])],-1),n('<h1 id="魔核之力-1" tabindex="-1">魔核之力 <a class="header-anchor" href="#魔核之力-1" aria-label="Permalink to &quot;魔核之力&quot;">​</a></h1><p>魔核之力<br> 【唯心的生物能——“魔力？”】<br> 魔力是魔核世界的特有能量，这种只能由生命合成的能量，性质便是“由心而定”，使用者的想法可以直接影响该能量的效果。<br> 也就是说魔力本身虽然有固定的量，但是同样多的魔力，所能产生的效果是不同的。<br> 作为完全唯心的能量，其效果无上限也无下限。理论上，一只魔核草履虫也能释放远超太阳的热量。<br> 既然这样，为什么世界还没有毁灭？</p><p>D级：凝聚魔核<br> 价格：D+1100<br> 思维钢印：每一个能够使用魔力的生物都拥有近乎无限的力量，因此为了避免危险发生，你的思想被永久打上印记，认为魔力只能产生兑换得到程度的效果。<br> “就像锁链一样，你的思维被其约束，但是‘束缚’并不一定等于‘不自由’，只要形式正确的话，也可以成为锁子甲。”<br> 你视为具有D级免疫心灵来源影响的能力。<br> 魔核：你的体内被植入了一枚满是沟壑，密布血管和神经的粉白色浑浊晶体，从此以后可以产生魔力与掌控力。<br> 你开启魔力能量池，与其他魔力能量池不同，这一能量池的关键属性是耐力+决心，在长休息后会自动恢复至满值，或在短休息进行一次关键属性检定，恢复成功数点魔力。</p><p>魔力的基础用法<br> 消耗2点魔力，你使用一个迅捷使用，在本轮内获得传奇决心*1点的全检定加值。</p><p>C级：种族极致<br> 价格：C+1800<br> 凝聚力：抵达种族极限的生物，在拥有强大的凝聚力与领导力。<br> 与你初次见面的单位初始好感将提升1级计算，最高不超过友善态度 这是一个C级信息来源带来的影响效果。</p><p>魔核-提升：异常灵智，极致体魄，再生肉身，更高效的魔力利用，一切的一切源自于魔力。<br> 你现在可以在使用基础用法时，将消耗6点，此时全检定加值提升至传奇决心*2，动作消耗降低至自由动作，持续时间提升至一场景。<br> 持续时间内，你还会额外获得1点快速医疗效果（医疗点12）。</p><p>B级：贵人<br> 价格：B+2400<br> 高等生物：魔核人中的上位种族，金发碧瞳白肤长耳，身形修长。在侧脸有蔓延至脖颈与耳尖的闪烁碎晶，言行举止能轻易赢得生物尊敬和崇拜，消除他们的情绪，并激发正面或负面情感；擅长洞察生物内心想法，接收或传递生物情绪。</p><p>你可以直接干涉他人的情感，这是一个B级信息来源的思维控制效果。<br> 具体用法为：在战斗外或战斗内，你可以使用任意社交检定与对方的意志豁免进行对抗，只要在这其中取得了任意成功数，就可以自由调节对方对于某个单位的好感上升或下降2级，重复检定可以叠加好感变化，但无法上升或下降到极端态度，受影响的单位不会主动去寻找态度改变的原因，但可以被其他人提醒。<br> 如果对方因外力介入意识到了态度变化的问题，可以重新进行一次对抗，对抗成功则回归之前的态度等级，但如果失败，则态度等级依旧无法转变（即使明知道这是不正确的）。<br> 这个效果只对非轮回者的单位有效。<br> 你可以在使用这个效果时额外支付一个迅捷动作，如果受到影响的单位位于你周边的30米范围内，则被影响的单位获得B级心灵来源的免疫效果（包括自身）。</p><p>改良种：这是经过大量学者反复调整修改，最合适的进化形态，可在低氧，辐射的极端环境正常生存，营养吸收率≥95%；新陈代谢仅为常人的30%；可主动控制体重波动在±20公斤范围内。因此，你获得了B级环境免疫的能力。</p><p>魔核—提升：取代先前本改造的魔力基础用法（即先前的基础用法失效），只要你的魔力池不空，你的魔力就会带来外貌的提升，你的外貌提升决心附加成功*10点。</p><p>魔力研究报告<br> 10<br> 【无意识无穷效果与认知稳定场】<br> 魔力的应用分为两种，分别为刻意的，与无意的。<br> 无意的应用，导致魔核生物潜意识对世界的认识带来的现实扭曲。<br> 每个魔核生物对世界的看法，都会在无意间变成一种效果覆盖在现实上。比如说“我有两只眼睛，左眼因为受过伤所以瞎了”“人类会在三十岁左右开始变老，最多活不过二百岁”“长远来看，万物都会腐朽”“<br> 从古至今，所有魔核生物对于世界的认识层层叠加，形成了覆盖在自然规则上的“认知稳定场”，“认知稳定场”重新制定了万物的规则，令魔核生命可按照规则成长、进化以及应用魔力，但也为万物加上了框架，降低了魔核生命的可能性。</p><p>认知稳定场制定了魔核世界的超凡规则，但魔力作为没有上限的唯心能，为何没有直接将整个世界塑造成更符合魔核文明的地心论，而仍然是宇宙的形态？</p><p>【为何有未知？世界的三层构造】<br> 人无法想象未曾见过的事物，在魔核世界中，是不该存在“未知”的。没有任何人见过的东西，会被认知稳定场所抹除，假如没有任何人见过沙漠中存在生命，那么沙漠中原本存在的生命，以及这些生命的存在痕迹都会消失。<br> 魔力可以随意且无上限的重塑现实，任何魔核生物都可以把亿万光年的宇宙塑造成不到0.01光年的地心论世界，或者把地心论世界塑造成宇宙世界。<br> 但事实上，魔核世界仍然存在广袤的未知，世界也仍然是宇宙世界，而非魔核文明认为的地心论世界。<br> 这是由于一种凌驾于魔力的意志笼罩整个宇宙，稳定所有自然规则，压制魔核生命发挥出“不该有的水平”，而不是草履虫都能撕裂星河。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
